// ============================================
// HELPER FUNCTIONS
// ============================================

// Get all transactions for a specific date
export const getByDate = (date) =>
  transactions.filter((t) => t.date === date);

// Get all transactions for a specific patient name
export const getByPatient = (name) =>
  transactions.filter((t) =>
    t.patientName.toLowerCase().includes(name.toLowerCase())
  );

// Get total revenue for a specific date
export const getDailyRevenue = (date) =>
  transactions
    .filter((t) => t.date === date && t.status !== "Failed")
    .reduce((sum, t) => sum + t.amount, 0);

// Get revenue grouped by payment method for a date
export const getRevenueByMethod = (date) => {
  const filtered = transactions.filter(
    (t) => t.date === date && t.status !== "Failed"
  );
  return {
    Cash: filtered
      .filter((t) => t.method === "Cash")
      .reduce((s, t) => s + t.amount, 0),
    Telebirr: filtered
      .filter((t) => t.method === "Telebirr")
      .reduce((s, t) => s + t.amount, 0),
    eBirr: filtered
      .filter((t) => t.method === "eBirr")
      .reduce((s, t) => s + t.amount, 0),
  };
};

// Get monthly revenue summary
export const getMonthlyRevenue = (year, month) => {
  const prefix = `${year}-${String(month).padStart(2, "0")}`;
  return transactions
    .filter((t) => t.date.startsWith(prefix) && t.status !== "Failed")
    .reduce((sum, t) => sum + t.amount, 0);
};

// Get status counts for a date
export const getStatusCounts = (date) => {
  const filtered = transactions.filter((t) => t.date === date);
  return {
    Paid: filtered.filter((t) => t.status === "Paid").length,
    Verified: filtered.filter((t) => t.status === "Verified").length,
    Pending: filtered.filter((t) => t.status === "Pending").length,
    Failed: filtered.filter((t) => t.status === "Failed").length,
    Total: filtered.length,
  };
};

// Get last N transactions
export const getRecentTransactions = (n = 10) =>
  [...transactions].reverse().slice(0, n);

// Get daily revenue for chart — last 30 days
export const getLast30DaysRevenue = () => {
  const days = [];
  const start = new Date("2026-12-01");
  for (let i = 0; i < 30; i++) {
    const d = new Date(start);
    d.setDate(start.getDate() + i);
    const dateStr = d.toISOString().split("T")[0];
    days.push({
      date: dateStr,
      revenue: getDailyRevenue(dateStr),
    });
  }
  return days;
};
